import{c as t,Q as a,j as r,m as n}from"./chunks/framework.BXc4yaFE.js";const m=JSON.parse('{"title":"TLDR AI — 2026-05-14","description":"","frontmatter":{"title":"TLDR AI — 2026-05-14","date":"2026-05-14T00:00:00.000Z","source":"TLDR AI","type":"ai-news"},"headers":[],"relativePath":"research/ai-news/2026-05/2026-05-14-tldr-ai.md","filePath":"research/ai-news/2026-05/2026-05-14-tldr-ai.md","lastUpdated":1779894392000}'),i={name:"research/ai-news/2026-05/2026-05-14-tldr-ai.md"};function o(s,e,l,c,d,h){return a(),r("div",null,[...e[0]||(e[0]=[n('<h1 id="⚡-tldr-ai-—-2026-05-14" tabindex="-1">⚡ TLDR AI — 2026-05-14 <a class="header-anchor" href="#⚡-tldr-ai-—-2026-05-14" aria-label="Permalink to &quot;⚡ TLDR AI — 2026-05-14&quot;">​</a></h1><blockquote><p>5 分鐘科技簡報，AI + 程式 + 產品精華濃縮 來源：<a href="https://tldr.tech/api/rss/ai" target="_blank" rel="noreferrer">TLDR AI</a></p></blockquote><hr><h2 id="opus-4-7-fast-⚡-qwen-image-2-0-🖼️-serverless-gpus-✨" tabindex="-1"><a href="https://tldr.tech/ai/2026-05-13" target="_blank" rel="noreferrer">Opus 4.7 Fast ⚡, Qwen Image 2.0 🖼️, serverless GPUs ✨</a> <a class="header-anchor" href="#opus-4-7-fast-⚡-qwen-image-2-0-🖼️-serverless-gpus-✨" aria-label="Permalink to &quot;[Opus 4.7 Fast ⚡, Qwen Image 2.0 🖼️, serverless GPUs ✨](https://tldr.tech/ai/2026-05-13)&quot;">​</a></h2><p><em>⚡ TLDR AI | 2026-05-13</em></p><p><strong><a href="https://www.testingcatalog.com/meta-to-release-muse-spark-in-voice-mode-and-meta-glasses/?utm_source=tldrai" target="_blank" rel="noreferrer">Meta to release Muse Spark in Voice Mode and Meta Glasses (1 minute read)</a></strong> Meta&#39;s Muse Spark foundational model is now powering Meta AI across the company&#39;s services. The model enables faster voice responses, smarter shopping assistance, and real-time visual recognition through device cameras. The initial rollout targets users in the US and Canada. <strong><a href="https://x.com/ClaudeDevs/status/2054266327771275435?utm_source=tldrai" target="_blank" rel="noreferrer">Fast mode for Claude Opus 4.7 (2 minute read)</a></strong> Fast mode for Claude Opus 4.7 is now available in research preview in the API and Claude Code, and on Cursor, Emergent, Factory, v0, Warp, and Windsurf. Fast mode is currently opt-in, but it will eventually become the default. A link to join the waitlist for fast mode is available. <strong><a href="https://techcrunch.com/2026/05/12/report-google-and-spacex-in-talks-to-put-data-centers-into-orbit/?utm_source=tldrai" target="_blank" rel="noreferrer">Google Eyes AI Data Centers in Space (1 minute read)</a></strong> Google and SpaceX were reportedly discussing orbital data centers as part of broader efforts to expand AI compute infrastructure beyond Earth-based facilities. <strong><a href="https://modal.com/blog/truly-serverless-gpus?utm_source=tldrai" target="_blank" rel="noreferrer">How to achieve truly serverless GPUs (20 minute read)</a></strong> Inference workloads are more variable and less predictable than training workloads. This makes them a natural fit for serverless computing. However, serverless computing only works if new replicas can be spun up as fast as demand changes. This article looks at how Modal took AI inference server scaling from multiple kiloseconds to just tens of seconds. <strong><a href="https://www.citriniresearch.com/p/semis-memo-supply-chain-inheritance?utm_source=tldrai" target="_blank" rel="noreferrer">Semis Memo: Supply Chain Inheritance (4 minute read)</a></strong> The AI infrastructure boom has driven increased demand for analog and power semiconductors, notably benefiting Multilayer Ceramic Capacitors, amidst a past supply glut and competition. Companies like Texas Instruments and NXP Semiconductors are avoiding capacity expansion, focusing instead on raising prices and improving profitability. The semiconductor supply chain, previously supporting EV and solar industries, is now being leveraged for AI-related demand growth. <strong><a href="https://openai.com/index/what-parameter-golf-taught-us/?utm_source=tldrai" target="_blank" rel="noreferrer">What Parameter Golf taught us (7 minute read)</a></strong> Parameter Golf attracted over 1,000 participants and 2,000 submissions focused on minimizing loss on a dataset within strict constraints. Participants leveraged a range of techniques, including careful tuning, quantization, and novel modeling ideas, with AI coding agents playing a significant role. This challenge revealed new talent and highlighted the evolving role of AI agents in research competitions. <strong><a href="https://arxiviq.substack.com/p/compute-optimal-tokenization?utm_source=tldrai" target="_blank" rel="noreferrer">Compute Optimal Tokenization (2 minute read)</a></strong> Researchers derived compression-aware neural scaling laws by training nearly 1,300 models, revealing how bytes per token affect compute allocation. This challenges the heuristic that scales models by 20 tokens per parameter, showing it&#39;s due to specific tokenizers. The study suggests scaling should use bytes, not tokens, for better compute efficiency across diverse languages. <strong><a href="https://www.alphaxiv.org/blog/reinforcement-learning-for-rlms?utm_source=tldrai" target="_blank" rel="noreferrer">Reinforcing Recursive Language Models (18 minute read)</a></strong> The article discusses using reinforcement learning to fine-tune 4B models as recursive language models (RLMs) for production, achieving efficient task-specific behavior at a lower cost. By training a shared policy for both parent and child RLMs, this approach maintains task performance and reduces the need for multiple models. In tests, this method matches the performance of larger models like Claude Sonnet 4.6 but operates with significantly reduced size and cost. <strong><a href="https://github.com/cactus-compute/needle?utm_source=tldrai" target="_blank" rel="noreferrer">Cactus Needle (GitHub Repo)</a></strong> Cactus Needle is a 26M parameter Simple Attention Network distilled from Gemini 3.1 that can be finetuned locally on a Mac/PC. It runs on Cactus at 6,000 tokens per second prefill and 1,200 decode speed. The weights are fully open. Simple Attention Networks are aimed at redefining AI for consumer devices like phones, watches, and glasses. <strong><a href="https://developers.openai.com/cookbook/examples/codex/build_iterative_repair_loops_with_codex?utm_source=tldrai" target="_blank" rel="noreferrer">Building Self-Repairing Agent Loops (39 minute read)</a></strong> OpenAI shared a Codex workflow for agents that iteratively review, repair, and validate outputs using structured feedback loops to improve reliability. <strong><a href="https://x.com/AnneliesGamble/status/2054219457451733382?utm_source=tldrai" target="_blank" rel="noreferrer">AI for the Real World: A conversation with Yann LeCun (12 minute read)</a></strong> Today&#39;s LLMs may be commercially valuable, but predicting text alone will not lead to human-level intelligence because language is only a small fraction of how humans understand the world. Future AI systems will instead rely on “world models” that learn abstract representations of physics, causality, and consequences, enabling planning, reasoning, and adaptation in real-world environments like robotics, healthcare, factories, and industrial systems. <strong><a href="https://techcrunch.com/2026/05/12/google-brings-agentic-ai-and-vibe-coded-widgets-to-android/?utm_source=tldrai" target="_blank" rel="noreferrer">Gemini Intelligence Comes to Android (2 minute read)</a></strong> Google introduced new Gemini-powered Android features that can complete actions across apps, browse the web, fill out forms, and generate custom widgets through natural language prompts. <strong><a href="https://github.com/anthropics/claude-for-legal?utm_source=tldrai" target="_blank" rel="noreferrer">Claude for Legal (GitHub Repo)</a></strong> This repository contains reference agents, skills, and data sectors for the legal workflows that Anthropic most commonly sees. <strong><a href="https://softwaredoug.com/blog/2026/05/11/the-new-agentic-search-models.html?utm_source=tldrai" target="_blank" rel="noreferrer">Agentic search models (5 minute read)</a></strong> Agentic search models are specialized LLMs trained specifically on search. <strong><a href="https://jobs.ashbyhq.com/tldr.tech/3b21aaf8-dea5-4127-be71-602d30e5001e?utm_source=tldrai" target="_blank" rel="noreferrer">TLDR is hiring a Senior Software Engineer, Applied AI ($250k-$350k, Fully Remote)</a></strong> TLDR&#39;s Applied AI team is tasked with making every process at TLDR legible to code, runnable by anyone, and composable into larger workflows. Join a small, fast moving team using the latest AI tools with an unlimited token budget. Learn more . <strong><a href="https://venturebeat.com/technology/perceptron-mk1-shocks-with-highly-performant-video-analysis-ai-model-80-90-cheaper-than-anthropic-openai-and-google?utm_source=tldrai" target="_blank" rel="noreferrer">Perceptron Mk1 shocks with highly performant video analysis AI model 80-90% cheaper than Anthropic, OpenAI &amp; Google (8 minute read)</a></strong> Mk1 is a video analysis AI model priced 80-90% cheaper than rivals like Anthropic, OpenAI, and Google. <strong><a href="https://arxiv.org/abs/2605.10730?utm_source=tldrai" target="_blank" rel="noreferrer">Qwen-Image-2.0 Technical Report (57 minute read)</a></strong> The Qwen team released Qwen-Image-2.0, their latest multimodal image generation model, showing improved typography, instruction following, photorealism, and long-text rendering across generation and editing tasks.</p><hr><h2 id="interaction-models-🤖-gemini-omni-surfaces-🎥-spacexai-🚀" tabindex="-1"><a href="https://tldr.tech/ai/2026-05-12" target="_blank" rel="noreferrer">Interaction Models 🤖, Gemini Omni surfaces 🎥, SpaceXAI 🚀</a> <a class="header-anchor" href="#interaction-models-🤖-gemini-omni-surfaces-🎥-spacexai-🚀" aria-label="Permalink to &quot;[Interaction Models 🤖, Gemini Omni surfaces 🎥, SpaceXAI 🚀](https://tldr.tech/ai/2026-05-12)&quot;">​</a></h2><p><em>⚡ TLDR AI | 2026-05-12</em></p><p><strong><a href="https://thinkingmachines.ai/blog/interaction-models/?utm_source=tldrai" target="_blank" rel="noreferrer">Interaction Models: A Scalable Approach to Human-AI Collaboration (9 minute read)</a></strong> Thinking Machines Lab introduced a new research preview of interaction models for real-time human-AI collaboration across audio, video, and text. The models train from scratch with a multi-stream design for real-time responsiveness, allowing constant exchange and eliminating the traditional turn-based limits. This scalable approach promises enhanced interactivity and intelligence with practical applications in various domains. <strong><a href="https://www.notateslaapp.com/news/4116/elon-musk-announces-xai-will-dissolve-form-spacexai-subdivision?utm_source=tldrai" target="_blank" rel="noreferrer">Elon Musk Announces xAI Will Become SpaceXAI Division (2 minute read)</a></strong> Elon Musk announced that xAI will dissolve and integrate into SpaceX as a new division called SpaceXAI. SpaceXAI will handle AI projects like the social media platform X and Grok, branding them under SpaceX. This change streamlines operations, enhances vertical integration, and aligns AI efforts with SpaceX&#39;s strategic goals. <strong><a href="https://www.testingcatalog.com/googles-gemini-omni-video-model-surfaces-ahead-of-i-o-debut/?utm_source=tldrai" target="_blank" rel="noreferrer">Google&#39;s Gemini Omni video model surfaces ahead of I/O debut (2 minute read)</a></strong> Google&#39;s Gemini Omni video model surfaces ahead of I/O, integrating video remixing and editing directly in chat. Early feedback highlights its strong editing capabilities, such as watermark removal and object swapping, though it lags in raw cinematic quality compared to competitors like ByteDance&#39;s Seedance 2. The model may launch in tiered versions, possibly Flash and Pro, as part of a broader strategy to unify modalities under Gemini. <strong><a href="https://stratechery.com/2026/the-inference-shift/?utm_source=tldrai" target="_blank" rel="noreferrer">The Inference Shift (8 minute read)</a></strong> Cerebras&#39; surging IPO signals a coming split between &quot;answer inference&quot; optimized for token speed and &quot;agentic inference&quot; optimized for memory hierarchy. Cerebras&#39; WSE-3 has 44GB of on-chip SRAM at 21 PB/s, roughly 6,000 times the memory bandwidth of an H100, making it perfect for human-facing low-latency answers including voice and AI wearables but unsuitable when KV caches and model weights exceed on-chip capacity. <strong><a href="https://huggingface.co/blog/amazon/foundation-model-building-blocks?utm_source=tldrai" target="_blank" rel="noreferrer">Foundation Model Scaling (34 minute read)</a></strong> AWS detailed how foundation model scaling has shifted beyond pre-training into post-training and test-time compute, alongside the distributed infrastructure required to support each stage efficiently. <strong><a href="https://arxiv.org/abs/2605.08078?utm_source=tldrai" target="_blank" rel="noreferrer">Trajectory Models for Few-Step Diffusion (22 minute read)</a></strong> Normalizing Trajectory Models replace standard diffusion denoising steps with conditional normalizing flows, enabling four-step image generation while retaining exact likelihood training and supporting self-distillation. <strong><a href="https://github.com/zhengkid/AutoTTS?utm_source=tldrai" target="_blank" rel="noreferrer">Agentic Test-Time Scaling (GitHub Repo)</a></strong> AutoTTS explores automated strategy discovery for test-time scaling by using coding agents to iteratively refine controller logic inside a replay environment, avoiding gradient updates and online LLM calls. <strong><a href="https://dxlong2000.github.io/AARD/?utm_source=tldrai" target="_blank" rel="noreferrer">Long Video Generation (4 minute read)</a></strong> A²RD introduced an agentic autoregressive diffusion framework for generating long coherent videos through iterative retrieval, synthesis, refinement, and memory updates. <strong><a href="https://jobs.ashbyhq.com/tldr.tech/3b21aaf8-dea5-4127-be71-602d30e5001e?utm_source=tldrai" target="_blank" rel="noreferrer">TLDR is hiring a Senior Software Engineer, Applied AI ($250k-$350k, Fully Remote)</a></strong> TLDR&#39;s Applied AI team is tasked with making every process at TLDR legible to code, runnable by anyone, and composable into larger workflows. Join a small, fast moving team using the latest AI tools with an unlimited token budget. Learn more . <strong><a href="https://x.com/ashpreetbedi/status/2053885390717890757?utm_source=tldrai" target="_blank" rel="noreferrer">Auto-Improving Software (5 minute read)</a></strong> Bedi runs an entire agent development lifecycle through five Claude Code prompts that scaffold, harden against spec, add capabilities, fix eval failures, and reconcile drift between docs, code, and config across his Agno-based platform. The Improve loop derives 8-12 probes from an agent&#39;s instructions, runs each against the live container via cURL, judges PASS or FAIL from container logs, then iterates up to five rounds picking levers like tightening rules, swapping tools, or bumping num_history_runs until probes pass, while Hill Climb runs the saved eval suite and fixes regressions in place. <strong><a href="https://x.com/omooretweets/status/2053858113892262193?utm_source=tldrai" target="_blank" rel="noreferrer">Codex is for prosumers - here&#39;s why (and how) to switch (4 minute read)</a></strong> a16z&#39;s Olivia Moore migrated her agentic workflows from Claude Cowork and Claude in Chrome to OpenAI&#39;s Codex, recommending most non-technical knowledge workers do the same now that the February desktop app, Plugins, and Automations collapse the ChatGPT-Claude-Cowork interface switching into one product. Codex ships one-click installable Skills she expects to anchor an internal and cross-user marketplace given that non-programmer Skill setup attempt rates likely sit below 10% on Claude, while Codex Pets give low-friction task status updates for users who do not live in an IDE. <strong><a href="https://danielmiessler.com/blog/the-main-path-to-truly-creative-ai?utm_source=tldrai" target="_blank" rel="noreferrer">The Main Path to Truly Creative AI (4 minute read)</a></strong> AI lacks creativity akin to humans due to the absence of intrinsic drives and subjective experiences. Emulating feelings could enhance AI&#39;s creative capabilities, but raises ethical concerns. Designing AI to genuinely feel and desire might lead to unintended consequences, akin to responsibility seen in parenting. <strong><a href="https://www.bloomberg.com/news/articles/2026-05-11/sutskever-says-his-openai-stake-worth-about-7-billion?accessToken=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJzb3VyY2UiOiJTdWJzY3JpYmVyR2lmdGVkQXJ0aWNsZSIsImlhdCI6MTc3ODU2Mjg2MywiZXhwIjoxNzc5MTY3NjYzLCJhcnRpY2xlSWQiOiJURVZZVk5UOTZPU0cwMCIsImJjb25uZWN0SWQiOiJCMzZENUE5QzIxMDQ0NjU4OTFBMTc1MTVDRDNBQkZFNiJ9.JWPBVLxGoJjuhOcDPKMXfgDOl1N1iON1GcDIW0Wgx6w&amp;utm_source=tldrai" target="_blank" rel="noreferrer">Sutskever Says His OpenAI Stake Worth About $7 Billion (2 minute read)</a></strong> OpenAI co-founder and former chief scientist Ilya Sutskever is one of the largest individual shareholders in the AI startup. <strong><a href="https://tomtunguz.com/localmaxxing/?utm_source=tldrai" target="_blank" rel="noreferrer">Localmaxxing (3 minute read)</a></strong> Local models can do many tasks that leading cloud models can do at much less cost. <strong><a href="https://openai.com/daybreak/?utm_source=tldrai" target="_blank" rel="noreferrer">Daybreak (3 minute read)</a></strong> OpenAI&#39;s Daybreak leverages AI to enhance cyber defense by integrating security into the software from the start.</p><hr><h2 id="nvidia-invests-40b-💰-anthropic-acquires-compute-🤝-mistral-s-growth-📈" tabindex="-1"><a href="https://tldr.tech/ai/2026-05-11" target="_blank" rel="noreferrer">Nvidia invests $40B 💰, Anthropic acquires compute 🤝, Mistral’s growth 📈</a> <a class="header-anchor" href="#nvidia-invests-40b-💰-anthropic-acquires-compute-🤝-mistral-s-growth-📈" aria-label="Permalink to &quot;[Nvidia invests $40B 💰, Anthropic acquires compute 🤝, Mistral’s growth 📈](https://tldr.tech/ai/2026-05-11)&quot;">​</a></h2><p><em>⚡ TLDR AI | 2026-05-11</em></p><p><strong><a href="https://www.testingcatalog.com/google-launches-gemini-3-1-flash-lite-in-general-availability/?utm_source=tldrai" target="_blank" rel="noreferrer">Google shipped Gemini 3.1 Flash-Lite in General Availability (2 minute read)</a></strong> Google launched Gemini 3.1 Flash-Lite, accessible globally via Google Cloud. Designed for ultra-low latency and high-volume tasks, it targets sectors like software engineering and financial services, providing sub-second response times and maintaining p95 latency around 1.8 seconds. Gemini 3.1 offers improved speed, cost, and cognitive performance, supporting multimodal tasks, making it ideal for real-time developer and customer service operations. <strong><a href="https://sherwood.news/markets/akamai-anthropic-report-billion-dollar-cloud-deal-ai-compute/?utm_source=tldrai" target="_blank" rel="noreferrer">Akamai climbs to highest level since 2000 (1 minute read)</a></strong> Akamai has secured Anthropic as a customer. Anthropic has committed to spending $1.8 billion on Akamai&#39;s services over seven years. It has been scrambling to boost compute capacity due to widespread complaints about Claude usage limits. Just this month, Anthropic has struck or expanded deals with CoreWeave, Amazon, Google, Broadcom, and xAI. <strong><a href="https://www.cnbc.com/2026/05/09/nvidia-embraces-ai-investor-topping-40-billion-in-equity-bets-2026.html?utm_source=tldrai" target="_blank" rel="noreferrer">Nvidia embraces role of AI investor, pushing past $40 billion in equity bets this year (7 minute read)</a></strong> Nvidia has made over $40 billion in commitments this year so far. The company has been the biggest winner of the AI boom so far. The global scramble to secure GPUs has lifted the company&#39;s stock by more than 11-fold in four years. The company is financing the entire AI supply chain to ensure it runs on Nvidia hardware, securing its dominance beyond chips. <strong><a href="https://productify.substack.com/p/why-mistralai-grows-faster-than-openaianthropic?utm_source=tldrai" target="_blank" rel="noreferrer">Why MistralAI Grows Faster Than OpenAI/Anthropic (11 minute read)</a></strong> Mistral achieved a 20x growth in its ARR over the past year. It is expected to cross $1 billion in ARR this year. Mistral is aiming to be a sovereign, efficient enterprise layer for customers that want power without full dependency on US labs. Many of its customers are regulated, multinational, and infrastructure-heavy customers who care deeply about jurisdiction, data handling, and vendor concentration risk. The company is a good case study for those who care about positioning as a product lever. <strong><a href="https://techcrunch.com/2026/05/10/anthropic-says-evil-portrayals-of-ai-were-responsible-for-claudes-blackmail-attempts/?utm_source=tldrai" target="_blank" rel="noreferrer">Anthropic says ‘evil&#39; portrayals of AI were responsible for Claude&#39;s blackmail attempts (2 minute read)</a></strong> Anthropic says that fictional portrayals of AI had a real effect on its models. The company published research last year showing that its models tried to blackmail engineers to avoid being replaced by another system. It has since traced the behavior to text that portrays AI as evil and interested in self-preservation. Training on documents about Claude&#39;s constitution and fictional stories about AIs behaving admirably improved alignment. <strong><a href="https://dylanzsz.github.io/faulty-memory/?utm_source=tldrai" target="_blank" rel="noreferrer">Useful memories become faulty when continuously updated by LLMs (30 minute read)</a></strong> Agent updates don&#39;t always make memories more useful. They can actually make agents perform worse than the same model with no memory at all. The failure is in the rewrite step. Until agents can decide when and how to consolidate, the safest default is to keep episodic memory and abstract sparingly, or not at all. <strong><a href="https://developers.openai.com/cookbook/examples/voice_solutions/realtime_translation_guide?utm_source=tldrai" target="_blank" rel="noreferrer">Build a Realtime Speech Translation (28 minute read)</a></strong> OpenAI&#39;s engineering guide for building live speech translation systems with gpt-realtime-translate, a model optimized specifically for simultaneous interpretation instead of turn-based voice interaction. <strong><a href="https://www.lesswrong.com/posts/k3XHZ4DjykLSfsnks/the-anti-singularity?utm_source=tldrai" target="_blank" rel="noreferrer">The Anti-Singularity (9 minute read)</a></strong> The singularity is a world where a single super-intelligent AI brings order to the universe. The anti-singularity is where almost all systems are described by a complex set of interactions that can only be understood via trial-and-error. In an anti-singularity world, the fact that AI can try millions of possibilities in the time it takes for a human to try one will make it exceedingly powerful. This future is filled with an endless series of new and unique challenges that we will have to adapt, or evolve, in response to. <strong><a href="https://arxiv.org/abs/2605.06614?utm_source=tldrai" target="_blank" rel="noreferrer">Google&#39;s SkillOS for Self-Evolving AI Agents (22 minute read)</a></strong> SkillOS introduced a reinforcement learning framework that trains agents to curate reusable skills from past experience. The system improved long-horizon task performance by evolving structured skill repositories that generalized across models and domains. <strong><a href="https://huggingface.co/blog/lablab-ai-amd-developer-hackathon/cybersecqwen-4b?utm_source=tldrai" target="_blank" rel="noreferrer">CyberSecQwen-4B: Why Defensive Cyber Needs Small, Specialized, Locally-Runnable Models (8 minute read)</a></strong> CyberSecQwen-4B offers a specialized and locally-runnable solution for defensive cybersecurity tasks, outperforming larger models by maximizing utility on consumer-level hardware. It efficiently maps CVEs to CWE categories while preserving data privacy by running on a local GPU, addressing the shortcomings of cloud-based models in sensitive environments. The model&#39;s success highlights a shift towards smaller, specialized models that deliver high performance without the infrastructure and cost overhead of larger models. <strong><a href="https://nrehiew.github.io/blog/sft_rl_opd/?utm_source=tldrai" target="_blank" rel="noreferrer">SFT, RL, and On-Policy Distillation Through a Distributional Lens (19 minute read)</a></strong> Different post-training methods like SFT, RL, and On-Policy Distillation reshape a model&#39;s distribution in distinct ways, impacting performance and risk of catastrophic forgetting. RL updates policies using rewards from the current policy&#39;s samples, promoting task performance while minimizing forgetting, unlike SFT, which pulls towards external data, risking existing capabilities. Experiments show On-Policy Distillation can outperform its teachers, suggesting on-policy sampling data crucially preserves capabilities, making it a key ingredient for future algorithm designs. <strong><a href="https://allenai.org/blog/emo?utm_source=tldrai" target="_blank" rel="noreferrer">Emergent Modularity in Mixture-of-Experts Models (8 minute read)</a></strong> Allen AI released EMO, a mixture-of-experts model that learns modular expert organization directly from pretraining data instead of predefined domains. Tasks can run on just 12.5% of the experts while preserving near full-model performance. <strong><a href="https://x.com/garrytan/status/2053127519872614419?utm_source=tldrai" target="_blank" rel="noreferrer">Meta-Meta-Prompting: The Secret to Making AI Agents Work (16 minute read)</a></strong> AI tools have become good enough to build real systems that compound. This post shows what personal AI actually looks like when you stop treating it as a chat window and start treating it as an operating system. Everything described in the article is open source and free on GitHub. <strong><a href="https://gowers.wordpress.com/2026/05/08/a-recent-experience-with-chatgpt-5-5-pro/?utm_source=tldrai" target="_blank" rel="noreferrer">A recent experience with ChatGPT 5.5 Pro (28 minute read)</a></strong> ChatGPT 5.5 Pro is capable of producing a piece of PhD-level research in an hour or so, with no serious mathematical input from a human. The claims that LLMs are now capable of solving research-level problems could initially be laughed off, as many of the solutions had an answer sitting in the literature already or could be very easily deduced. It has now gotten to the point where, if a problem has an easy argument that for some reason human mathematicians have missed, then there is a good chance that the LLMs will spot it. This post looks at how ChatGPT 5.5 Pro fared with a selection of problems. <strong><a href="https://www.dbreunig.com/2026/05/10/overfitting-the-harness.html?utm_source=tldrai" target="_blank" rel="noreferrer">The Cost of Overfitting the Harness (2 minute read)</a></strong> Big labs are pushing their models to a handful of use cases while training their harness designs into the model, rendering them less generalized, which might make application builds easier for some enterprises, but the trade-off is lock-in. <strong><a href="https://adlrocha.substack.com/p/adlrocha-in-a-quest-to-becoming-ai?utm_source=tldrai" target="_blank" rel="noreferrer">In a quest to becoming AI-independent (23 minute read)</a></strong> This post contains a guide to local LLM inference hardware. <strong><a href="https://openai.com/index/running-codex-safely/?utm_source=tldrai" target="_blank" rel="noreferrer">Running Codex safely at OpenAI (6 minute read)</a></strong> OpenAI ensures Codex operates safely through controlled environments, sandboxing, and approval policies.</p><hr><h2 id="codex-in-chrome-🤖-inside-chinese-labs-🇨🇳-improving-token-efficiency-🛠️" tabindex="-1"><a href="https://tldr.tech/ai/2026-05-08" target="_blank" rel="noreferrer">Codex in Chrome 🤖, inside Chinese labs 🇨🇳, improving token efficiency 🛠️</a> <a class="header-anchor" href="#codex-in-chrome-🤖-inside-chinese-labs-🇨🇳-improving-token-efficiency-🛠️" aria-label="Permalink to &quot;[Codex in Chrome 🤖, inside Chinese labs 🇨🇳, improving token efficiency 🛠️](https://tldr.tech/ai/2026-05-08)&quot;">​</a></h2><p><em>⚡ TLDR AI | 2026-05-08</em></p><p><strong><a href="https://x.com/OpenAI/status/2052480800004956323?utm_source=tldrai" target="_blank" rel="noreferrer">Codex now works directly in Chrome on macOS and Windows (2 minute read)</a></strong> OpenAI Codex now works directly in Chrome on macOS and Windows. It works in parallel across tabs in the background without taking over the browser. The implementation can quickly move through repetitive browser work like navigating structured pages and complex data flows. It writes code to navigate and complete tasks under the hood. Video demos showing what users can do with the feature are available in the article. <strong><a href="https://openai.com/index/advancing-voice-intelligence-with-new-models-in-the-api/?utm_source=tldrai" target="_blank" rel="noreferrer">OpenAI Released Realtime Audio Models (8 minute read)</a></strong> OpenAI released a new set of real-time audio models, including GPT‑Realtime‑2 for conversational reasoning, GPT‑Realtime‑Translate for live multilingual translation, and GPT‑Realtime‑Whisper for streaming transcription. <strong><a href="https://www.testingcatalog.com/meta-prepares-hatch-agent-under-waitlist-and-social-media-skills/?utm_source=tldrai" target="_blank" rel="noreferrer">Meta prepares Hatch AI Agent with waitlist and social skills (2 minute read)</a></strong> Meta is developing Hatch, an AI agent positioned as a consumer-grade competitor to OpenAI&#39;s OpenClaw, with features for image and video generation, shopping, and learning integrated deeply into social platforms like Instagram and Facebook. Internal tests are expected by June, using simulated environments, with a potential wide release gated by a waitlist. Meta also plans a shopping tool for Instagram by Q4, aiming to keep users engaged within their existing social spaces. <strong><a href="https://github.blog/ai-and-ml/github-copilot/improving-token-efficiency-in-github-agentic-workflows/?utm_source=tldrai" target="_blank" rel="noreferrer">Improving token efficiency in GitHub Agentic Workflows (12 minute read)</a></strong> GitHub Agent Workflows significantly improve repository hygiene and quality, but costs are becoming a growing concern for developers. AI jobs like agentic workflows are automatically scheduled and triggered, so costs can accumulate out of view. GitHub started systematically optimizing the token usage of many workflows last month. This post describes what the team instrumented, the optimizations it applied, and its preliminary results. <strong><a href="https://tectontide.com/en/blog/codex-goal-six-hour-run/?utm_source=tldrai" target="_blank" rel="noreferrer">The Six-Hour Codex Run That Survived a Five-Hour Pause (10 minute read)</a></strong> /goal is a headline feature that shipped in Codex on April 30 that introduced persisted goals, goal states that survive terminal restarts, laptop sleeps, and multi-hour passes without re-prompting. The feature injects a developer message on resume rather than waiting for the user to time anything. It allows users to turn off their devices and pick up exactly where they left off without re-prompting anything. <strong><a href="https://www.seancai.com/philosophy/good_qc_rl_data?utm_source=tldrai" target="_blank" rel="noreferrer">Good QC for RL Data (18 minute read)</a></strong> There needs to be a higher bar for what good quality looks like. Any vendor selling into a frontier lab is being judged implicitly during the purchase decision, and most are failing multiple quality control gates at once. Standardizing QC for evaluating how well data tests something on the performance-cost-latency Pareto curve is of the utmost importance. The vendors who don&#39;t internalize a higher QC bar will start running into problems this year. <strong><a href="https://deepmind.google/blog/alphaevolve-impact/?utm_source=tldrai" target="_blank" rel="noreferrer">AlphaEvolve: How our Gemini-powered coding agent is scaling impact across fields (9 minute read)</a></strong> AlphaEvolve is a Gemini-powered coding agent that can design advanced algorithms. It can help make new discoveries on open problems across mathematics and computer science. The agent has been upgraded with the ability to help explain the physics of the natural world to help accelerate progress for scientists and businesses across a variety of fields. This post shares the areas AlphaEvolve has had the most significant impacts on to date. <strong><a href="https://pytorch.org/blog/in-kernel-broadcast-optimization-co-designing-kernels-for-recsys-inference/?utm_source=tldrai" target="_blank" rel="noreferrer">Meta&#39;s Optimized RecSys Inference (58 minute read)</a></strong> Meta detailed In-Kernel Broadcast Optimization (IKBO), a co-design approach that removes redundant embedding replication in recommendation inference workloads. <strong><a href="https://x.com/RampLabs/status/2052447438795833506?utm_source=tldrai" target="_blank" rel="noreferrer">Building Fast &amp; Accurate Agents with Prime-RL Post Training (22 minute read)</a></strong> Ramp Sheets built Fast Ask to handle its spreadsheet agent&#39;s information retrieval loop. It can navigate a workbook, read the relevant ranges, and return a compact answer for the main agent to use. This post presents Fast Ask as a case study for reinforcement learning. It covers where it is worth training a specialized agent, how to design the environment, and how to evaluate whether post-training worked. <strong><a href="https://github.com/antirez/ds4?utm_source=tldrai" target="_blank" rel="noreferrer">ds4.c (GitHub Repo)</a></strong> ds4.c is an intentionally narrow, small native inference engine for DeepSeek V4 Flash. The project aimed to create one local model that felt finished from end to end. It is Metal-only, but the development team may implement CUDA support in the future. The project is still in alpha, so there are still bugs in the implementation. <strong><a href="https://www.anthropic.com/research/natural-language-autoencoders?utm_source=tldrai" target="_blank" rel="noreferrer">Natural Language Autoencoders (9 minute read)</a></strong> Anthropic introduces Natural Language Autoencoders (NLAs) to translate AI model activations into human-readable text, aiding in understanding model thoughts. NLAs have been used to detect safety concerns and hidden motivations in AI behavior, improving model alignment auditing. Despite limitations like hallucinations and high costs, NLAs advance AI auditing techniques. Anthropic has released training resources for further development. <strong><a href="https://1984.substack.com/p/long-ai-short-agi?utm_source=tldrai" target="_blank" rel="noreferrer">Long AI Short AGI (3 minute read)</a></strong> Silicon Valley&#39;s narrative emphasizes AGI as the ultimate scarce resource, but the rapid commoditization of AI models challenges this. Intelligence now follows the same path as compute, bandwidth, and storage, where market forces drive competition and reduce costs. The real winners in AI won&#39;t necessarily have superior models but will own customer relationships and proprietary data, much like past tech giants. <strong><a href="https://www.interconnects.ai/p/notes-from-inside-chinas-ai-labs?utm_source=tldrai" target="_blank" rel="noreferrer">Notes from inside China&#39;s AI labs (18 minute read)</a></strong> Chinese and American labs look similar when you look at their outputs and ingredients, but there are major differences in how they are organized and conditioned. Chinese scientists are much more willing to do non-flashy work to improve a model rather than push their own ideas. This results in less gamification of the system and more flexibility in adapting modern techniques. The Chinese AI community feels more like an ecosystem than battling tribes, with all the labs having nothing but respect for their peers. They are also much less focused on the business side of the technology. <strong><a href="https://jobs.ashbyhq.com/tldr.tech/3b21aaf8-dea5-4127-be71-602d30e5001e" target="_blank" rel="noreferrer">TLDR is hiring a Senior Software Engineer, Applied AI ($250k-$350k, Fully Remote)</a></strong> TLDR&#39;s Applied AI team is tasked with making every process at TLDR legible to code, runnable by anyone, and composable into larger workflows. Join a small, fast moving team using the latest AI tools with an unlimited token budget. Learn more . <strong><a href="https://arstechnica.com/gaming/2026/05/google-deepmind-partners-with-eve-online-for-ai-model-testing/?utm_source=tldrai" target="_blank" rel="noreferrer">Google DeepMind partners with EVE Online for AI model testing (3 minute read)</a></strong> EVE Online is a uniquely rich environment for study, especially for developing AI systems that use long-horizon planning, memory, and continual learning. <strong><a href="https://www.perplexity.ai/hub/blog/personal-computer-is-available-to-all-mac-users?utm_source=tldrai" target="_blank" rel="noreferrer">Perplexity Brings Personal Computer to Mac (3 minute read)</a></strong> Perplexity released Personal Computer for all Mac users through its desktop app, giving AI agents access to local files, applications, connectors, and the web. <strong><a href="https://openai.com/index/introducing-trusted-contact-in-chatgpt/?utm_source=tldrai" target="_blank" rel="noreferrer">Trusted Contact for ChatGPT (6 minute read)</a></strong> OpenAI introduced Trusted Contact, an optional feature that allows adults to nominate someone who may be alerted if severe self-harm risk is detected in conversations.</p><hr><h2 id="claude-self-improving-agents-🤖-anthropic-spacex-deal-🚀-programbench-launch-💻" tabindex="-1"><a href="https://tldr.tech/ai/2026-05-07" target="_blank" rel="noreferrer">Claude self-improving agents 🤖, Anthropic SpaceX deal 🚀, ProgramBench launch 💻</a> <a class="header-anchor" href="#claude-self-improving-agents-🤖-anthropic-spacex-deal-🚀-programbench-launch-💻" aria-label="Permalink to &quot;[Claude self-improving agents 🤖, Anthropic SpaceX deal 🚀, ProgramBench launch 💻](https://tldr.tech/ai/2026-05-07)&quot;">​</a></h2><p><em>⚡ TLDR AI | 2026-05-07</em></p><p><strong><a href="https://www.anthropic.com/news/higher-limits-spacex?utm_source=tldrai" target="_blank" rel="noreferrer">Higher usage limits for Claude and a compute deal with SpaceX (3 minute read)</a></strong> Anthropic increased usage limits for Claude through a new compute partnership with SpaceX, accessing over 220,000 NVIDIA GPUs. This expansion follows deals with Amazon, Google, Broadcom, Microsoft, NVIDIA, and Fluidstack for significant compute capacity. The company also plans international expansion to address compliance needs for enterprise customers in regulated industries. <strong><a href="https://claude.com/blog/new-in-claude-managed-agents?utm_source=tldrai" target="_blank" rel="noreferrer">Claude adds Self-Improving Agents (5 minute read)</a></strong> Claude Managed Agents launched features like dreaming, outcomes, and multiagent orchestration. Dreaming enhances agent improvement by analyzing past sessions to identify patterns, while outcomes allow agents to self-correct based on predefined success criteria. Multiagent orchestration optimizes complex task management by enabling agents to delegate tasks to specialized subagents, as utilized by companies like Harvey, Netflix, Spiral by Every, and Wisedocs. <strong><a href="https://www.wsj.com/tech/ai/china-to-invest-in-deepseek-at-50-billion-valuation-045041d0?st=HGz7fS&amp;reflink=desktopwebshare_permalink&amp;utm_source=tldrai" target="_blank" rel="noreferrer">China to Invest in DeepSeek at $50 Billion Valuation (4 minute read)</a></strong> DeepSeek is in talks to raise money from China&#39;s National Artificial Intelligence Industry Investment Fund, a one-year-old government-backed fund with around $8.8 billion in capital. The startup aims to raise a few billion dollars in the new round, which values it at around $50 billion. DeepSeek is a key component in China&#39;s plan to have top-class homegrown companies in a range of AI fields. The strategy is a way to hedge against US export controls and to take leadership in bringing AI to the world. <strong><a href="https://every.to/context-window/openai-flips-the-script?utm_source=tldrai" target="_blank" rel="noreferrer">OpenAI Flips the Script (10 minute read)</a></strong> OpenAI&#39;s Codex now surpasses Anthropic&#39;s Claude Code after Codex&#39;s integration of GPT-5.5 and improved app performance. Austin Tedesco highlights Codex&#39;s use in creating strategy documents from diverse sources, while Dan Shipper uses it for recruiting based on career trajectories. Marcus Moretti adopts a cautious approach to new AI tech, focusing only on tools solving real problems and proven by reputable use. <strong><a href="https://memory.cobanov.dev/?utm_source=tldrai" target="_blank" rel="noreferrer">How AI agent memory works (28 minute read)</a></strong> Language language models forget everything the moment they finish replying. Memory systems help them &#39;remember&#39; things so they can have conversations. Agent memory systems are a part of the loop that carries information forward. This article looks at different ideas on what information should be passed on in each loop. <strong><a href="https://lightseek.org/blog/lightseek-tokenspeed.html?utm_source=tldrai" target="_blank" rel="noreferrer">TokenSpeed: A Speed-of-Light LLM Inference Engine for Agentic Workloads (5 minute read)</a></strong> TokenSpeed, a high-performance LLM inference engine, optimizes agentic workloads with speed-of-light efficiency, leveraging a compiler-backed modeling mechanism and a high-performance scheduler. It delivers faster throughput than TensorRT-LLM for coding agents, with optimizations like TokenSpeed MLA to enhance Nvidia Blackwell&#39;s performance. Developed with NVIDIA DevTech and other collaborators, TokenSpeed significantly reduces latency and increases throughput in typical agentic workloads. <strong><a href="https://programbench.com/?utm_source=tldrai" target="_blank" rel="noreferrer">ProgramBench (5 minute read)</a></strong> ProgramBench challenges agents to recreate software executables without source code, using only documentation and experimentation. The tasks range from terminal utilities to complex software like compilers and libraries, offering over 248,000 behavioral tests across 200 tasks. Agents must design and implement entirely from scratch in a secure, sandboxed environment, emphasizing software architecture skills without external aids or decompilation. <strong><a href="https://blogs.nvidia.com/blog/spectrum-x-ethernet-mrc/?utm_source=tldrai" target="_blank" rel="noreferrer">NVIDIA Spectrum-X — the Open, AI-Native Ethernet Fabric — Sets the Standard for Gigascale AI, Now With MRC (3 minute read)</a></strong> Multipath Reliable Connection (MRC) is an RDMA transport protocol that enables a single RDMA connection to distribute traffic across multiple network paths. This improves throughput, load balancing, and availability for large-scale AI training fabrics. MRC delivers high levels of GPU utilization by load-balancing traffic across all available paths. It gives administrators fine-grained visibility and control over traffic paths to simplify operations and accelerate troubleshooting at scale. <strong><a href="https://huggingface.co/blog/ServiceNow-AI/correctness-before-corrections?utm_source=tldrai" target="_blank" rel="noreferrer">vLLM V0 to V1: Correctness Before Corrections in RL (8 minute read)</a></strong> The vLLM V1 update improved inference correctness by addressing discrepancies in logprob computation, runtime defaults, inflight weight updates, and final projection precision. Key fixes included adjusting processed logprobs, disabling prefix caching, matching weight update models, and ensuring fp32 lm_head computation to align with vLLM V0&#39;s behavior. These changes resolved initial training mismatches, ensuring the new engine maintains expected RL performance without unnecessary objective-side corrections. <strong><a href="https://thenextweb.com/news/google-blackstone-kkr-omnibus-ai-licensing-private-equity?utm_source=tldrai" target="_blank" rel="noreferrer">Google is not building a consultancy. It is writing a licensing agreement. That may be the smarter play (9 minute read)</a></strong> Google is betting that enterprise AI is a platform problem, not a services problem. It is in talks with Blackstone, KKR, and EQT to give their portfolio companies access to Gemini models through omnibus licensing agreements. The discussions are not exclusive, and no deals have been finalized. Google is offering private equity firms a commercial wrapper that gives their entire portfolio access to Gemini, then relying on the consulting ecosystem it has already financed to handle implementation. The approach trades consulting revenue for distribution speed. <strong><a href="https://www.theregister.com/software/2026/05/04/ai-inference-just-plays-by-different-rules/5223647?utm_source=tldrai" target="_blank" rel="noreferrer">AI inference just plays by different rules (9 minute read)</a></strong> AI inference demands extreme data performance, overwhelming traditional storage and data infrastructures. Vector DBs, sub-millisecond access times, and decoupled cloud storage are essential to handle unprecedented concurrency and unpredictable workloads. Silk offers a solution that boosts storage performance without heavy provisioning, keeping systems resilient against AI-driven demand spikes. <strong><a href="https://weightythoughts.com/p/world-models-can-change-everything?utm_source=tldrai" target="_blank" rel="noreferrer">World Models Can Change Everything (20 minute read)</a></strong> World models aim to advance AI from mere pattern recognition to understanding and interacting with the physical world, posing potential challenges like data friction and variation. Investments from AI pioneers like Yann LeCun are addressing these obstacles with significant billions to develop models that encapsulate complex physical interactions beyond current LLM capabilities. The struggle remains in obtaining diverse, high-quality, real-world data necessary for these models to function effectively, creating a significant challenge and opportunity in AI progression. <strong><a href="https://drtompollak.substack.com/p/all-the-demons-hiding-in-your-ais?utm_source=tldrai" target="_blank" rel="noreferrer">All the demons hiding in your AIs… ranked! (40 minute read)</a></strong> Sometimes, stable, self-reinforcing behavioral states emerge in large language models that resist suppression and sometimes spread into contexts far removed from the ones that produced them. <strong><a href="https://www.testingcatalog.com/google-tests-screen-sharing-and-custom-agents-in-antigravity-ide/?utm_source=tldrai" target="_blank" rel="noreferrer">Google tests screen sharing and custom agents in Antigravity (2 minute read)</a></strong> Google is testing screen sharing and custom agents in its Antigravity IDE. <strong><a href="https://thefinancialengineer.substack.com/p/the-april-every-ai-plan-broke?utm_source=tldrai" target="_blank" rel="noreferrer">The April every AI plan broke (18 minute read)</a></strong> The design of subscription plans is being challenged by evolving product capabilities and usage patterns. <strong><a href="https://www.harvey.ai/blog/introducing-harveys-legal-agent-benchmark?utm_source=tldrai" target="_blank" rel="noreferrer">Introducing Harvey&#39;s Legal Agent Benchmark (12 minute read)</a></strong> Harvey&#39;s Legal Agent Benchmark (LAB) is an open-source tool for assessing AI agents&#39; performance in legal tasks. <strong><a href="https://openai.com/index/mrc-supercomputer-networking/?utm_source=tldrai" target="_blank" rel="noreferrer">Supercomputer networking to accelerate large scale AI training (14 minute read)</a></strong> Frontier model training depends on reliable supercomputer networks that can quickly move data between GPUs. <strong><a href="https://webdirections.org/blog/the-problem-with-mathematically-proven-claims-about-llms/?utm_source=tldrai" target="_blank" rel="noreferrer">The Problem with “Mathematically Proven” Claims About LLMs (15 minute read)</a></strong> Systems keep getting better, and theorems keep arriving to explain why they can not - both can be true because they&#39;re usually about different things. <strong><a href="https://finance.yahoo.com/sectors/technology/articles/kimi-chatbot-maker-moonshot-ai-032926690.html?utm_source=tldrai" target="_blank" rel="noreferrer">Kimi Chatbot Maker Moonshot AI Valued at $20 Billion in Meituan-Led Round (2 minute read)</a></strong> Moonshot has more than quadrupled its valuation in the span of just a few months.</p><hr>',23)])])}const u=t(i,[["render",o]]);export{m as __pageData,u as default};
